private struct PerplexityChatScreen: View {
    @State private var draft = ""
    var body: some View {
        VStack(spacing: 0) {
            ScrollView {
                VStack(spacing: 12) {
                    ForEach(PerplexityDemoData.messages) { msg in
                        if msg.isUser { PerplexityUserBubble(text: msg.text, accent: PerplexityTokens.pplxTextPrimary) }
                        else { PerplexityAssistantBubble(text: msg.text, surface: PerplexityTokens.pplxSurface1) }
                    }
                }.padding()
            }.background(PerplexityTokens.pplxCanvas.ignoresSafeArea())
            HStack(spacing: 12) {
                TextField("Message Perplexity…", text: $draft, axis: .vertical).padding(10).background(RoundedRectangle(cornerRadius: 20).fill(PerplexityTokens.pplxSurface1))
                Button {} label: { Image(systemName: "arrow.up.circle.fill").font(.title2).foregroundStyle(PerplexityTokens.pplxTextPrimary) }
            }.padding().background(.bar)
        }
    }
}

private struct PerplexityUserBubble: View {
    let text: String; let accent: Color
    var body: some View { HStack { Spacer(minLength: 48); Text(text).padding(12).background(RoundedRectangle(cornerRadius: 16).fill(accent.opacity(0.15))) } }
}

private struct PerplexityAssistantBubble: View {
    let text: String; let surface: Color
    var body: some View { HStack { Text(text).padding(12).background(RoundedRectangle(cornerRadius: 16).fill(surface)); Spacer(minLength: 48) } }
}

